178→CREATE OR REPLACE FUNCTION app.validate_against_patterns(
179→    p_tenant_id VARCHAR,
180→    p_audit JSONB
181→)
182→RETURNS TABLE(pattern_id UUID, severity VARCHAR, violation_detail JSONB) AS $$
183→DECLARE
184→    rec RECORD;
185→    text_blob TEXT;
186→    forbid_rule TEXT;
187→    require_rule TEXT;
188→BEGIN
189→    text_blob := lower(COALESCE(p_audit::text, ''));
190→
191→    FOR rec IN
192→        SELECT gp.pattern_id, gp.pattern_type, gp.constraint_json, gp.matcher_json, gp.severity
193→        FROM golden_patterns gp
194→        WHERE gp.tenant_id = p_tenant_id
195→          AND gp.is_active = true
196→    LOOP
197→        IF rec.matcher_json ? 'contains_text' THEN
198→            IF position(lower(rec.matcher_json->>'contains_text') in text_blob) = 0 THEN
199→                CONTINUE;
200→            END IF;
201→        END IF;
202→
203→        FOR forbid_rule IN
204→            SELECT jsonb_array_elements_text(COALESCE(rec.constraint_json->'forbid', '[]'::jsonb))
205→        LOOP
206→            IF text_blob ~* forbid_rule THEN
207→                pattern_id := rec.pattern_id;
208→                severity := rec.severity;
209→                violation_detail := jsonb_build_object(
210→                    'rule', 'forbid',
211→                    'pattern_type', rec.pattern_type,
212→                    'expr', forbid_rule
213→                );
214→                RETURN NEXT;
215→            END IF;
216→        END LOOP;
217→
218→        FOR require_rule IN
219→            SELECT jsonb_array_elements_text(COALESCE(rec.constraint_json->'require', '[]'::jsonb))
220→        LOOP
221→            IF NOT (text_blob ~* require_rule) THEN
222→                pattern_id := rec.pattern_id;
223→                severity := rec.severity;
224→                violation_detail := jsonb_build_object(
225→                    'rule', 'require',
226→                    'pattern_type', rec.pattern_type,
227→                    'expr', require_rule
228→                );
229→                RETURN NEXT;
230→            END IF;
231→        END LOOP;
232→    END LOOP;
233→END;
234→$$ LANGUAGE plpgsql;
235→
236→CREATE OR REPLACE FUNCTION app.record_pattern_violations(
237→    p_tenant_id VARCHAR,
238→    p_job_id INTEGER,
239→    p_audit JSONB
240→)
241→RETURNS TABLE(highest_severity VARCHAR, violation_count INTEGER) AS $$
242→DECLARE
243→    v_count INTEGER;
244→    v_rank INTEGER;
245→BEGIN
246→    WITH violations AS (
247→        SELECT * FROM app.validate_against_patterns(p_tenant_id, p_audit)
248→    ), ins AS (
249→        INSERT INTO pattern_violations (tenant_id, job_id, pattern_id, severity, violation_detail)
250→        SELECT p_tenant_id, p_job_id, v.pattern_id, v.severity, v.violation_detail
251→        FROM violations v
252→        RETURNING severity
253→    )
254→    SELECT count(*),
255→           COALESCE(max(CASE severity WHEN 'WARN' THEN 1 WHEN 'FAIL' THEN 2 WHEN 'ESCALATE' THEN 3 ELSE 0 END), 0)
256→      INTO v_count, v_rank
257→    FROM ins;
258→
259→    violation_count := COALESCE(v_count, 0);
260→    highest_severity := CASE v_rank WHEN 3 THEN 'ESCALATE' WHEN 2 THEN 'FAIL' WHEN 1 THEN 'WARN' ELSE 'OK' END;
261→    RETURN NEXT;
262→END;
263→$$ LANGUAGE plpgsql;
264→
265→GRANT EXECUTE ON FUNCTION app.validate_against_patterns(VARCHAR, JSONB) TO app_user;
266→GRANT EXECUTE ON FUNCTION app.record_pattern_violations(VARCHAR, INTEGER, JSONB) TO app_user;
