 1→-- migrations/015_auto_partition_function.sql
 2→-- 今月+来月+再来月のパーティションを自動生成する関数
 3→
 4→CREATE SCHEMA IF NOT EXISTS app;
 5→
 6→CREATE OR REPLACE FUNCTION app.ensure_audit_partitions()
 7→RETURNS void
 8→LANGUAGE plpgsql
 9→AS $$
10→DECLARE
11→  month_offset integer;
12→  partition_name text;
13→  range_start date;
14→  range_end date;
15→BEGIN
16→  FOR month_offset IN 0..2 LOOP
17→    range_start := date_trunc('month', now() + (month_offset || ' months')::interval)::date;
18→    range_end := (range_start + interval '1 month')::date;
19→    partition_name := 'audit_trails_y' || to_char(range_start, 'YYYY') || 'm' || to_char(range_start, 'MM');
20→    IF NOT EXISTS (
21→      SELECT 1 FROM pg_class WHERE relname = partition_name
22→    ) THEN
23→      EXECUTE format(
24→        'CREATE TABLE IF NOT EXISTS %I PARTITION OF audit_trails FOR VALUES FROM (%L) TO (%L)',
25→        partition_name, range_start, range_end
26→      );
27→      RAISE NOTICE 'Created partition: %', partition_name;
28→    END IF;
29→  END LOOP;
30→END;
31→$$;
32→
33→-- マイグレーション適用時に即時実行
34→SELECT app.ensure_audit_partitions();
